<?php
$row = is_array($row ?? null) ? $row : [];
$lines = is_array($lines ?? null) ? $lines : [];
$money = static function ($value): string { return 'Rp ' . number_format((float)$value, 0, ',', '.'); };
$qty = static function ($value, int $decimals = 2): string { return number_format((float)$value, $decimals, ',', '.'); };
$dt = static function ($value): string { $time = $value ? strtotime((string)$value) : false; return $time ? date('d M Y H:i', $time) : '-'; };
$this->load->view('pos/_report_styles');
?>

<div class="container-xxl py-3"><div class="pos-report-shell"><div class="pos-report-hero mb-3"><div class="d-flex flex-wrap justify-content-between gap-3"><div><div class="pos-report-title">Detail Refund POS</div><p class="pos-report-copy mb-0">Dokumen refund lengkap beserta line produk dan extra yang dibatalkan.</p></div><a href="<?php echo site_url('pos/reports/refunds'); ?>" class="btn btn-outline-secondary">Kembali</a></div></div><?php $this->load->view('pos/_report_nav', ['report_nav_active' => 'refund']); ?><div class="row g-3 mb-3"><div class="col-lg-5"><div class="pos-report-section p-3 h-100"><div class="pos-report-kv"><strong>Refund</strong><span><?php echo html_escape((string)($row['refund_no'] ?? '-')); ?></span><strong>Order</strong><span><?php echo html_escape((string)($row['order_no'] ?? '-')); ?></span><strong>Member</strong><span><?php echo html_escape((string)($row['member_name'] ?? '-')); ?><?php echo !empty($row['member_no']) ? ' · ' . html_escape((string)$row['member_no']) : ''; ?></span><strong>Outlet</strong><span><?php echo html_escape((string)($row['outlet_name'] ?? '-')); ?></span><strong>Method</strong><span><?php echo html_escape((string)($row['method_name'] ?? '-')); ?></span><strong>Account</strong><span><?php echo html_escape((string)($row['company_account_name'] ?? '-')); ?></span><strong>Status</strong><span><?php echo html_escape((string)($row['refund_status'] ?? '-')); ?></span><strong>Refunded At</strong><span><?php echo html_escape($dt($row['refunded_at'] ?? null)); ?></span><strong>Reason</strong><span><?php echo html_escape((string)($row['reason'] ?? '-')); ?></span></div></div></div><div class="col-lg-7"><div class="row g-3"><div class="col-md-4"><div class="pos-report-card"><div class="pos-report-card-label">Refund Amount</div><div class="pos-report-card-value"><?php echo $money($row['refund_amount'] ?? 0); ?></div><div class="pos-report-card-note">Nilai refund dokumen.</div></div></div><div class="col-md-4"><div class="pos-report-card"><div class="pos-report-card-label">Return To Stock</div><div class="pos-report-card-value"><?php echo !empty($row['return_to_stock']) ? 'YA' : 'TIDAK'; ?></div><div class="pos-report-card-note">Apakah stok dikembalikan.</div></div></div><div class="col-md-4"><div class="pos-report-card"><div class="pos-report-card-label">Processed</div><div class="pos-report-card-value"><?php echo html_escape((string)($row['processed_state'] ?? '-')); ?></div><div class="pos-report-card-note">Status proses reversal stok.</div></div></div></div></div></div><div class="pos-report-section p-3"><h5 class="mb-3">Line Refund</h5><div class="pos-report-table-wrap"><div class="table-responsive"><table class="table table-sm align-middle mb-0 pos-report-table"><thead><tr><th>Line</th><th>Item</th><th>Tipe</th><th class="text-end">Qty</th><th class="text-end">Amount</th><th class="text-end">Cost Reversed</th><th>Process</th><th>Catatan</th></tr></thead><tbody><?php if (empty($lines)): ?><tr><td colspan="8" class="text-center pos-report-empty">Belum ada line refund.</td></tr><?php else: ?><?php foreach ($lines as $line): ?><tr><td><?php echo (int)($line['line_no'] ?? 0); ?></td><td><div class="fw-semibold"><?php echo html_escape((string)($line['item_name'] ?? '-')); ?></div><div class="pos-report-meta"><?php echo !empty($line['order_line_no']) ? 'Order line #' . (int)$line['order_line_no'] : '-'; ?></div></td><td><?php echo html_escape((string)($line['line_type'] ?? '-')); ?></td><td class="text-end"><?php echo $qty($line['qty_refunded'] ?? 0, 0); ?></td><td class="text-end"><?php echo $money($line['amount_refunded'] ?? 0); ?></td><td class="text-end"><?php echo $money($line['cost_reversed'] ?? 0); ?></td><td><?php echo html_escape((string)($line['line_process_state'] ?? '-')); ?></td><td><?php echo html_escape((string)($line['notes'] ?? '-')); ?></td></tr><?php endforeach; ?><?php endif; ?></tbody></table></div></div></div></div></div>